import (
    "bytes"
    "encoding/json"
    "fmt"
    "html/template"
    "local-gin/utils"

    "github.com/gin-contrib/cors"
    "github.com/gin-gonic/gin"
)

func main() {
    r := gin.Default()
    corsConfig := cors.DefaultConfig()
    corsConfig.AllowAllOrigins = true
    corsConfig.AllowHeaders = []string{"*"}
    r.Use(cors.New(corsConfig))
    r.GET("/ping", func(c *gin.Context) {
        c.JSON(200, gin.H{
            "message": "pong",
        })
    })

    dbs := []string{"a", "b", "c", "d"}
    htmlString := `
    &lt;head&gt;
        &lt;link href="https://cdn.bootcdn.net/ajax/libs/monaco-editor/0.20.0/min/vs/editor/editor.main.min.css" rel="stylesheet"&gt;
    &lt;/head&gt;
    &lt;body style="margin: 0;"&gt;
        &lt;div
            style="height: 100vh;width: 100vw;display: grid; grid-template-columns: repeat(2, 1fr);grid-template-rows: 40px 1fr;"&gt;
            &lt;div style="display: flex;align-items: center; padding: 10px;"&gt;
                &lt;form method="post" id="play" style="margin:0;"&gt;
                    &lt;label for=""&gt;
                        DB:{{.DbValue}}
                        &lt;select name="db" id="db"&gt;
                        {{range .Dbs}}
                        &lt;option value="{{ . }}" {{if eq . $.DbValue }}selected{{end}}&gt;{{ . }}&lt;/option&gt;
                        {{end}}

                        &lt;/select&gt;
                    &lt;/label&gt;
                    &lt;input type="hidden" name="sql" id="sql" value="{{.Sql}}" /&gt;
                &lt;/form&gt;
            &lt;/div&gt;
            &lt;div style="display: flex; align-items: center;"&gt;
                &lt;input type="submit" form="play" value="Run" /&gt;
            &lt;/div&gt;
            &lt;div id="editor"&gt;&lt;/div&gt;
            &lt;div id="view"&gt;&lt;/div&gt;
        &lt;/div&gt;
        &lt;script src="https:///www.unpkg.com/monaco-editor@0.47.0/min/vs/loader.js"&gt;&lt;/script&gt;
        &lt;script&gt;
        require.config({ paths: { 'vs': 'https:///www.unpkg.com/monaco-editor@0.47.0/min/vs' } });
        require(['vs/editor/editor.main'], function () {
            sqlEditor = monaco.editor.create(document.getElementById('editor'), {
                value: '{{.Sql}}',
                      language: 'sql',
            });

            sqlEditor.onDidBlurEditorText(function(){
                document.querySelector('#sql').value = sqlEditor.getValue()
            })

            viewEditor = monaco.editor.create(document.getElementById('view'), {
                value: '{{.Result}}',
                      language: 'json',
                readOnly: true
            });
        })
        &lt;/script&gt;
    &lt;/body&gt;
    `
    type sqlData struct {
        Dbs     []string
        DbValue string `form:"db"`
        Sql     string `form:"sql"`
        Result  string
    }
    t, _ := template.New("edior").Parse(htmlString)
    run := r.Group("play")
    {
        run.GET("", func(ctx *gin.Context) {
            writer := bytes.NewBufferString("")
            t.Execute(writer, sqlData{
                Dbs: dbs,
            })
            ctx.Header("content-type", "text/html; charset=utf-8")
            ctx.String(200, writer.String())
        })

        run.POST("", func(ctx *gin.Context) {
            var params sqlData
            if err := ctx.ShouldBind(&amp;params); err != nil {
                fmt.Println(params)
                params.Result = err.Error()
            }
            if len(params.DbValue) == 0 || len(params.Sql) == 0 {
                params.Result = "参数错误"
            } else {
                db, err := utils.GetDBConnection(params.DbValue)
                if err != nil {
                    params.Result = err.Error()
                } else {
                    var result []map[string]interface{}
                    r := db.Raw(params.Sql).Find(&amp;result)
                    if r.Error != nil {
                        params.Result = r.Error.Error()
                    } else {
                        b, _ := json.MarshalIndent(result, "", "  ")
                        params.Result = string(b)
                    }
                }
            }

            writer := bytes.NewBufferString("")
            params.Dbs = dbs
            t.Execute(writer, params)
            ctx.Header("content-type", "text/html; charset=utf-8")
            ctx.String(200, writer.String())
        })
    }

    r.Run(":8200")
}
</code></pre>

helper/http.go<pre><code>package helper

import (
    "encoding/json"
    "fmt"
    "io"
    "net/http"
    "net/url"
    "strings"
)

type HTTPMethod int

const (
    GET HTTPMethod = iota
    POST
    PUT
    PATCH
    DELETE
)

func (s HTTPMethod) String() string {
    switch s {
    case GET:
        return "GET"
    case POST:
        return "POST"
    case PUT:
        return "PUT"
    case PATCH:
        return "PATCH"
    case DELETE:
        return "DELETE"
    }
    return "unknown"
}

func MakeHTTPRequest[T any](urlFull string, method string, headers map[string]string, query url.Values, body io.Reader, responseType T) (T, error) {
    client := http.Client{}

    // format url
    u, err := url.Parse(urlFull)
    if err != nil {
        return responseType, err
    }

    // format query
    q := u.Query()

    for k, v := range query {
        q.Set(k, strings.Join(v, ","))
    }
    u.RawQuery = q.Encode()

    // init http
    req, err := http.NewRequest(method, u.String(), body)
    if err != nil {
        return responseType, err
    }
    // init header
    for k, v := range headers {
        req.Header.Set(k, v)
    }
    // do request
    res, err := client.Do(req)
    if err != nil {
        return responseType, err
    }
    // warning empty response
    if res == nil {
        return responseType, fmt.Errorf("")
    }
    defer res.Body.Close()

    // no 200
    if res.StatusCode != http.StatusOK {
        return responseType, fmt.Errorf("")
    }
    // read body
    resP, err := io.ReadAll(res.Body)
    if err != nil {
        return responseType, err
    }

    var resO T
    err = json.Unmarshal(resP, &amp;resO)
    if err != nil {
        return responseType, err
    }

    return resO, nil
}
